// Script Continued Below
var ClientTaskRequest = Class.create();
ClientTaskRequest.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {

	getRequestIdToOpen: function(){

		var TaskSysId = this.getParameter("pTaskSysId");
		var RequestType = this.getParameter("pRequestType");
		var Status = this.getParameter("pStatus");

		var RequestSysId;

		var gr = new GlideRecordSecure('x_153465_discovert_tasker_requests');
		gr.addQuery('parent', TaskSysId);
		gr.addQuery('u_request_type', RequestType);
		gr.addQuery('u_status', Status);
		gr.query();

		while(gr.next()){
			RequestSysId = gr.sys_id;
		}
		return RequestSysId;
	},

	type: 'ClientTaskRequest'
});
